import{_ as e,o as t,c as a,d as r}from"./app.5504077d.js";const u='{"title":"\u0424\u043E\u043D\u0434 \u0424\u0420\u0423\u041A\u0422","description":"","frontmatter":{"title":"\u0424\u043E\u043D\u0434 \u0424\u0420\u0423\u041A\u0422","subtitle":"\u0424\u043E\u043D\u0434 \u0420\u0430\u0437\u0432\u0438\u0442\u0438\u044F \u0423\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438, \u041A\u043E\u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0438 \u0438 \u0422\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0430","list":"main","cover":"logo_stencil.svg"},"headers":[],"relativePath":"index.md"}',s={},_=r('<p><a href="./frukt/">\u0424\u043E\u043D\u0434 \u0424\u0420\u0423\u041A\u0422</a> \u2013 \u044D\u0442\u043E \u043D\u0435\u043A\u043E\u043C\u043C\u0435\u0440\u0447\u0435\u0441\u043A\u0430\u044F \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u044F \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438, \u043A\u043E\u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0438 \u0438 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0430 \u0432 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0435 \u0438 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435.</p><p>\u0421 2012 \u0433\u043E\u0434\u0430 \u043C\u044B \u043F\u0440\u043E\u0432\u043E\u0434\u0438\u043C <a href="./research/">\u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F</a>, \u0440\u0430\u0437\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u0435\u043C <a href="./designs/">\u0441\u043E\u0446\u0438\u043E-\u043A\u0443\u043B\u044C\u0442\u0443\u0440\u043D\u044B\u0435 \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u044B</a> \u0438 \u043F\u043E \u043C\u0435\u0440\u0435 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0435\u0439 \u0437\u0430\u043D\u0438\u043C\u0430\u0435\u043C\u0441\u044F \u0438\u0445 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0435\u0439.</p><p>\u0414\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u043C\u044B \u0441\u043E\u0431\u0438\u0440\u0430\u0435\u043C \u0438 \u043E\u0431\u043E\u0431\u0449\u0430\u0435\u043C \u043C\u0430\u0441\u0441\u0443 \u043A\u0430\u043A \u0442\u0435\u043E\u0440\u0435\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E, \u0442\u0430\u043A \u0438 \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430. \u0412 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u043C\u044B \u043D\u0430\u043A\u0430\u043F\u043B\u0438\u0432\u0430\u0435\u043C \u0446\u0435\u043D\u043D\u044B\u0435 \u0437\u043D\u0430\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u043C\u0438 \u0441\u0442\u0440\u0435\u043C\u0438\u043C\u0441\u044F \u0434\u0435\u043B\u0438\u0442\u044C\u0441\u044F \u0441 \u043C\u0438\u0440\u043E\u043C. \u0417\u0434\u0435\u0441\u044C \u043C\u044B \u043E\u0442\u043A\u0440\u044B\u0442\u043E \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u0442\u0438\u0437\u0438\u0440\u0443\u0435\u043C \u044D\u0442\u0438 \u0437\u043D\u0430\u043D\u0438\u044F \u0432 \u0435\u0434\u0438\u043D\u043E\u0439 \u0441\u0438\u0441\u0442\u0435\u043C\u0435. \u041D\u043E \u044D\u0442\u043E \u043D\u0435 \u0434\u043E\u0433\u043C\u0430, \u0430 \u0441\u043A\u043E\u0440\u0435\u0435 \u043E\u0442\u043F\u0440\u0430\u0432\u043D\u0430\u044F \u0442\u043E\u0447\u043A\u0430 \u0434\u043B\u044F \u0442\u0435\u0445, \u043A\u0442\u043E \u0445\u043E\u0442\u0435\u043B \u0431\u044B \u0441 \u043D\u0430\u043C\u0438 \u043F\u043E\u0433\u0440\u0443\u0437\u0438\u0442\u044C\u0441\u044F \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u043F\u0440\u0435\u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u0438\u044F \u0441\u0435\u0431\u044F \u0438 \u043C\u0438\u0440\u0430 \u0432\u043E\u043A\u0440\u0443\u0433.</p><p>\u0427\u0442\u043E\u0431\u044B \u0441\u043A\u043E\u043E\u0440\u0434\u0438\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E \u0434\u0432\u0438\u0433\u0430\u0442\u044C\u0441\u044F \u043A \u044F\u0441\u043D\u044B\u043C \u0446\u0435\u043B\u044F\u043C, \u043D\u0430\u043C \u0432\u0430\u0436\u043D\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u0434\u0440\u0443\u0433 \u0434\u0440\u0443\u0433\u0430. \u0414\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u043C\u044B \u0440\u0430\u0437\u0440\u0430\u0431\u044B\u0432\u0430\u0435\u043C \u043E\u0441\u043E\u0431\u044B\u0439 \u044F\u0437\u044B\u043A \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u043E\u0431\u0449\u0435\u043D\u0438\u044F \u043B\u044E\u0434\u0435\u0439 <a href="./discourse/">\u0424\u0440\u0443\u043A\u0442\u043E\u0432\u044B\u0439 \u0434\u0438\u0441\u043A\u0443\u0440\u0441</a>.</p><p>\u0412 \u043E\u0441\u043D\u043E\u0432\u0435 \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u043C\u043E\u0434\u0435\u043B\u0438 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044F \u0424\u043E\u043D\u0434\u0430 \u043B\u0435\u0436\u0430\u0442 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u044B \u0434\u043E\u0431\u0440\u043E\u0432\u043E\u043B\u044C\u043D\u043E\u0433\u043E \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0441\u043E\u0442\u0440\u0443\u0434\u043D\u0438\u0447\u0435\u0441\u0442\u0432\u0430. \u041E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u044B\u0439 \u043F\u043E\u0441\u0442\u0443\u043F\u043E\u043A \u0432\u043E \u0431\u043B\u0430\u0433\u043E \u0441\u0435\u0431\u044F \u0438 \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0438\u0445 \u043A\u0430\u043A \u0435\u0434\u0438\u043D\u043E\u0439 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u2013 \u0431\u0430\u0437\u043E\u0432\u0430\u044F \u0424\u0420\u0423\u041A\u0422\u043E\u0432\u0430\u044F \u0442\u0440\u0430\u043D\u0437\u0430\u043A\u0446\u0438\u044F. \u042D\u0442\u043E \u043D\u0435 \u044D\u043A\u0432\u0438\u0432\u0430\u043B\u0435\u0442\u043D\u044B\u0439 \u043E\u0431\u043C\u0435\u043D, \u044D\u0442\u043E \u043D\u043E\u0432\u044B\u0439 \u043F\u043E\u0434\u0445\u043E\u0434 \u043A \u0434\u0440\u0435\u0432\u043D\u0435\u0439\u0448\u0435\u0439 \u0444\u043E\u0440\u043C\u0435 \u043E\u0431\u043C\u0435\u043D\u0430 \u2013 <a href="./gifts/">\u044D\u043A\u043E\u043D\u043E\u043C\u0438\u043A\u0435 \u0434\u0430\u0440\u0430</a>, \u0433\u0434\u0435 \u0438 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442 \u0438 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C \u0443\u0447\u0430\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0433\u043E \u0432 \u043E\u0431\u043C\u0435\u043D\u0435 \u0438\u043C\u0435\u044E\u0442 \u0431\u043E\u043B\u044C\u0448\u043E\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435.</p><p>\u0418\u0437\u0443\u0447\u0430\u0442\u044C <a href="./research/gift-for-the-future/">\u0440\u043E\u043B\u044C \u0434\u0430\u0440\u0435\u043D\u0438\u044F \u0432 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435</a> - \u043D\u0435\u043F\u0440\u043E\u0441\u0442\u0430\u044F \u0437\u0430\u0434\u0430\u0447\u0430, \u0432\u0435\u0434\u044C \u0442\u0430\u043A \u043C\u0430\u043B\u043E \u043E\u0441\u0442\u0430\u043B\u043E\u0441\u044C \u043E\u0441\u0442\u0440\u043E\u0432\u043A\u043E\u0432 \u043D\u0435\u0442\u0440\u043E\u043D\u0443\u0442\u044B\u0445 \u0446\u0438\u0432\u0438\u043B\u0438\u0437\u0430\u0446\u0438\u0439, \u0433\u0434\u0435 \u043C\u043E\u0436\u043D\u043E \u0443\u0432\u0438\u0434\u0435\u0442\u044C \u0441\u043E\u0445\u0440\u0430\u043D\u0438\u0432\u0448\u0438\u0435\u0441\u044F \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438 \u0434\u0430\u0440\u0435\u043D\u0438\u044F. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u043C\u044B \u0432\u044B\u0431\u0438\u0440\u0430\u0435\u043C \u044D\u043A\u0441\u043F\u0435\u0440\u0438\u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0439 \u043F\u043E\u0434\u0445\u043E\u0434: \u043F\u0440\u043E\u0431\u043E\u0432\u0430\u0442\u044C \u043F\u043E-\u0440\u0430\u0437\u043D\u043E\u043C\u0443 \u0434\u0430\u0440\u0438\u0442\u044C \u0438 \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u044C \u0434\u0430\u0440\u044B, \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043D\u0430\u0431\u043B\u044E\u0434\u0430\u044F \u0437\u0430 \u0442\u0435\u043C, \u043A\u0430\u043A \u044D\u0442\u043E \u0432\u043B\u0438\u044F\u0435\u0442 \u043D\u0430 \u043D\u0430\u0441 \u0438 \u043D\u0430\u0448\u0438 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044F \u0434\u0440\u0443\u0433 \u0441 \u0434\u0440\u0443\u0433\u043E\u043C.</p>',6),o=[_];function c(i,p,n,f,d,h){return t(),a("div",null,o)}var m=e(s,[["render",c]]);export{u as __pageData,m as default};
